def range_summary(nums):
    if not nums:
        return ''

    nums.sort()
    ranges = []
    start = nums[0]

    for i in range(1, len(nums)):
        if nums[i] != nums[i - 1]:
            if nums[i - 1] == start:
                ranges.append(str(start))
            else:
                ranges.append(f"{start}-{nums[i - 1]}")
            start = nums[i]

    # Handle the last range
    if nums[-1] == start:
        ranges.append(str(start))
    else:
        ranges.append(f"{start}-{nums[-1]}")

    return ', '.join(ranges)
